import axios from 'axios';

// Create an axios instance with default configuration
const apiClient = axios.create({
  baseURL: process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:8000',
  timeout: 10000,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Request interceptor to add auth tokens if needed
apiClient.interceptors.request.use(
  (config) => {
    // You can add auth tokens here if needed
    // const token = localStorage.getItem('authToken');
    // if (token) {
    //   config.headers.Authorization = `Bearer ${token}`;
    // }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response interceptor for error handling
apiClient.interceptors.response.use(
  (response) => {
    return response;
  },
  (error) => {
    if (error.response?.status === 401) {
      // Handle unauthorized access
      console.error('Unauthorized access');
      // You might want to redirect to login page here
    } else if (error.response?.status === 500) {
      console.error('Server error occurred');
    } else if (error.code === 'ECONNABORTED') {
      console.error('Request timeout');
    } else if (error.code === 'ENOTFOUND' || error.code === 'ECONNREFUSED') {
      console.error('Failed to connect to server. Is the backend running on port 8000?');
    }
    return Promise.reject(error);
  }
);

// API endpoints
export const retirementApi = {
  calculateRetirement: async (data: any) => {
    try {
      // Correct path: /fourpercent/api/v1/retirement/fourpercentor/calculate
      const response = await apiClient.post('/fourpercent/api/v1/retirement/fourpercentor/calculate', data);

      // Ensure consistent null handling for years_to_depletion
      const result = response.data;
      if (result && typeof result.years_to_depletion === 'undefined') {
        result.years_to_depletion = null;
      }

      return result;
    } catch (error: any) {
      console.error('Error calculating retirement:', error);
      // Re-throw the error so the component can handle it
      throw error;
    }
  },
};

export const deepRetirementApi = {
  calculateDeepRetirement: async (data: any) => {
    try {
      // Path: /fourpercent/api/v2/deep_retirement/deep_retirement/calculate
      const response = await apiClient.post('/fourpercent/api/v2/deep_retirement/deep_retirement/calculate', data);

      return response.data;
    } catch (error: any) {
      console.error('Error calculating deep retirement:', error);
      throw error;
    }
  },
};

export default apiClient;
