import React, { useState } from 'react';
import { DeepRetirementInput, DeepRetirementProjection } from '@/lib/types/deep-retirement-types';

interface Scenario {
  id: string;
  name: string;
  input: DeepRetirementInput;
  projection: DeepRetirementProjection;
}

interface ScenarioComparisonProps {
  scenarios: Scenario[];
  onAddScenario?: () => void;
  onDeleteScenario?: (id: string) => void;
  onSelectScenario?: (id: string) => void;
}

const ScenarioComparison = ({
  scenarios,
  onAddScenario,
  onDeleteScenario,
  onSelectScenario
}: ScenarioComparisonProps) => {
  const [selectedScenarioId, setSelectedScenarioId] = useState<string | null>(null);

  const handleSelectScenario = (id: string) => {
    setSelectedScenarioId(id);
    onSelectScenario?.(id);
  };

  if (scenarios.length === 0) {
    return (
      <div className="bg-white p-6 rounded-lg shadow-md text-center">
        <p className="text-gray-500">No scenarios to compare. Add a scenario to get started.</p>
        {onAddScenario && (
          <button
            onClick={onAddScenario}
            className="mt-4 px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600"
          >
            Add Scenario
          </button>
        )}
      </div>
    );
  }

  // Get comparison metrics from the first scenario to determine which fields to show
  const comparisonMetrics = [
    { key: 'totalSavingsAtRetirement', label: 'Total Savings at Retirement' },
    { key: 'monthlyIncomeAtRetirement', label: 'Monthly Income' },
    { key: 'socialSecurityBenefit', label: 'Social Security' },
    { key: 'safeWithdrawalAmount', label: 'Safe Annual Withdrawal' },
    { key: 'projectedBalanceAtAge90', label: 'Projected Balance at 90' },
    { key: 'yearsToDepletion', label: 'Years to Depletion' },
  ];

  return (
    <div className="bg-white p-6 rounded-lg shadow-md">
      <h2 className="text-xl font-semibold mb-4">Scenario Comparison</h2>

      {/* Scenario Tabs */}
      <div className="flex overflow-x-auto gap-2 mb-6 pb-2">
        {scenarios.map((scenario) => (
          <button
            key={scenario.id}
            onClick={() => handleSelectScenario(scenario.id)}
            className={`px-4 py-2 rounded-lg whitespace-nowrap transition-colors ${
              selectedScenarioId === scenario.id
                ? 'bg-blue-500 text-white'
                : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
          >
            {scenario.name}
            <button
              onClick={(e) => {
                e.stopPropagation();
                onDeleteScenario?.(scenario.id);
              }}
              className="ml-2 text-red-500 hover:text-red-700"
            >
              ×
            </button>
          </button>
        ))}

        {onAddScenario && (
          <button
            onClick={onAddScenario}
            className="px-4 py-2 bg-green-500 text-white rounded-lg whitespace-nowrap hover:bg-green-600"
          >
            + Add Scenario
          </button>
        )}
      </div>

      {/* Comparison Table */}
      {selectedScenarioId && (
        <div className="overflow-x-auto">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-gray-100">
                <th className="p-3 text-left font-semibold">Metric</th>
                {scenarios.map((scenario) => (
                  <th key={scenario.id} className="p-3 text-center font-semibold">
                    {scenario.name}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {comparisonMetrics.map((metric) => (
                <tr key={metric.key} className="border-b hover:bg-gray-50">
                  <td className="p-3 text-gray-700">{metric.label}</td>
                  {scenarios.map((scenario) => {
                    const value = scenario.projection[metric.key as keyof DeepRetirementProjection];
                    return (
                      <td key={scenario.id} className="p-3 text-center font-medium">
                        {typeof value === 'number' ? formatCurrency(value) : value}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mt-6">
        {scenarios.map((scenario) => (
          <div
            key={scenario.id}
            onClick={() => handleSelectScenario(scenario.id)}
            className={`p-4 rounded-lg cursor-pointer transition-all ${
              selectedScenarioId === scenario.id
                ? 'bg-blue-50 border-2 border-blue-500'
                : 'bg-gray-50 hover:bg-gray-100 border border-gray-200'
            }`}
          >
            <h3 className="font-semibold text-lg mb-2">{scenario.name}</h3>
            <div className="space-y-1">
              <p className="text-sm text-gray-600">Savings at Retirement</p>
              <p className="font-bold text-green-700">
                {formatCurrency(scenario.projection.totalSavingsAtRetirement)}
              </p>
              <p className="text-sm text-gray-600 mt-2">Monthly Income</p>
              <p className="font-bold text-blue-700">
                {formatCurrency(scenario.projection.monthlyIncomeAtRetirement)}
              </p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

// Helper function to format currency
const formatCurrency = (value: number): string => {
  if (!value && value !== 0) return 'N/A';

  try {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(value);
  } catch (e) {
    console.error('Currency formatting error:', e);
    return `$${value.toLocaleString()}`;
  }
};

export default ScenarioComparison;
"}

{"path":"/home/rafid/devel/four_percentor/frontend/src/app/(main)/dashboard/retirement/_components/SensitivityAnalysisChart.tsx","content":"'use client';

import React, { useState } from 'react';
import { calculateFutureValueWithContributions } from '@/lib/calculation';

interface SensitivityAnalysisProps {
  currentSavings: number;
  monthlyContribution: number;
  annualReturnRate: number;
  yearsToRetirement: number;
}

const SensitivityAnalysisChart = ({
  currentSavings,
  monthlyContribution,
  annualReturnRate,
  yearsToRetirement
}: SensitivityAnalysisProps) => {
  const [returnRates, setReturnRates] = useState<number[]>([3, 5, 7, 9, 11]);

  // Calculate projections for different return rates
  const dataPoints = returnRates.map(rate => ({
    rate,
    futureValue: calculateFutureValueWithContributions(
      currentSavings,
      monthlyContribution,
      rate / 100,
      yearsToRetirement
    )
  }));

  // Find min and max values for chart scaling
  const maxValue = Math.max(...dataPoints.map(d => d.futureValue));
  const minValue = Math.min(...dataPoints.map(d => d.futureValue));

  return (
    <div className="bg-white p-6 rounded-lg shadow-md">
      <h2 className="text-xl font-semibold mb-4">Sensitivity Analysis</h2>
      <p className="text-sm text-gray-600 mb-4">
        How different annual return rates affect your retirement savings
      </p>

      {/* Chart */}
      <div className="relative h-64 w-full bg-gray-50 rounded-lg p-4 border border-gray-200">
        {/* Y-axis labels */}
        <div className="absolute left-0 top-0 bottom-0 flex flex-col justify-between py-8 text-xs text-gray-500">
          <span>{formatLargeNumber(maxValue)}</span>
          <span>{formatLargeNumber((maxValue + minValue) / 2)}</span>
          <span>{formatLargeNumber(minValue)}</span>
        </div>

        {/* Chart bars */}
        <div className="absolute left-8 right-0 top-0 bottom-0 flex items-end justify-around px-4">
          {dataPoints.map((point, index) => {
            const barHeightPercentage = 
              ((point.futureValue - minValue) / (maxValue - minValue || 1)) * 90 + 5;

            return (
              <div key={index} className="flex flex-col items-center gap-2 w-12">
                {/* Tooltip */}
                <div className="opacity-0 hover:opacity-100 absolute -mt-8 bg-gray-800 text-white text-xs rounded px-2 py-1 transition-opacity z-10 whitespace-nowrap">
                  {formatCurrency(point.futureValue)} @ {point.rate}% return
                </div>

                {/* Bar */}
                <div 
                  className="w-full bg-gradient-to-t from-blue-500 to-blue-300 rounded-t hover:from-blue-600 hover:to-blue-400 transition-all duration-300"
                  style={{ height: `${barHeightPercentage}%` }}
                />

                {/* X-axis label */}
                <div className="text-xs font-medium text-gray-700">{point.rate}%</div>
              </div>
            );
          })}
        </div>

        {/* Chart title */}
        <div className="absolute bottom-2 right-4 text-xs text-gray-500">
          Future Value at Retirement
        </div>
      </div>

      {/* Data table */}
      <div className="mt-6 overflow-x-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr className="bg-gray-100">
              <th className="p-3 text-left font-semibold">Return Rate</th>
              <th className="p-3 text-right font-semibold">Future Value</th>
              <th className="p-3 text-right font-semibold">Difference</th>
            </tr>
          </thead>
          <tbody>
            {dataPoints.map((point, index) => {
              const diff = index > 0 
                ? point.futureValue - dataPoints[index - 1].futureValue 
                : 0;

              return (
                <tr key={index} className="border-b hover:bg-gray-50">
                  <td className="p-3 font-medium">{point.rate}%</td>
                  <td className="p-3 text-right">{formatCurrency(point.futureValue)}</td>
                  <td className={`p-3 text-right ${diff > 0 ? 'text-green-600' : ''}`}>
                    {index > 0 ? (diff > 0 ? '+' : '') + formatCurrency(diff) : '-'}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Analysis insights */}
      <div className="mt-6 bg-blue-50 p-4 rounded-lg border-l-4 border-blue-500">
        <h3 className="font-semibold text-blue-900 mb-2">Key Insights</h3>
        <ul className="space-y-1 text-sm text-blue-800">
          <li>
            A {annualReturnRate + 2}% return would add approximately{' '}
            {formatCurrency(
              calculateFutureValueWithContributions(
                currentSavings, monthlyContribution, (annualReturnRate + 2) / 100, yearsToRetirement
              ) - dataPoints.find(d => d.rate === annualReturnRate)?.futureValue || 0
            )}
          </li>
          <li>
            A {annualReturnRate - 2}% return would result in approximately{' '}
            {formatCurrency(
              calculateFutureValueWithContributions(
                currentSavings, monthlyContribution, (annualReturnRate - 2) / 100, yearsToRetirement
              )
            )}
          </li>
          <li>
            The difference between a {Math.min(...returnRates)}% and {Math.max(...returnRates)}% 
            return could be over {formatCurrency(
              dataPoints[dataPoints.length - 1].futureValue - dataPoints[0].futureValue
            )} in today's dollars.
          </li>
        </ul>
      </div>
    </div>
  );
};

// Helper functions
const formatCurrency = (value: number): string => {
  if (!value && value !== 0) return 'N/A';

  try {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      maximumFractionDigits: 0
    }).format(value);
  } catch (e) {
    console.error('Currency formatting error:', e);
    return `$${value.toLocaleString()}`;
  }
};

const formatLargeNumber = (num: number): string => {
  if (num >= 1_000_000_000) {
    return `$${(num / 1_000_000_000).toFixed(1)}B`;
  } else if (num >= 1_000_000) {
    return `$${(num / 1_000_000).toFixed(1)}M`;
  } else if (num >= 1_000) {
    return `$${(num / 1_000).toFixed(1)}K`;
  }
  return `$${Math.round(num)}`;
};

export default SensitivityAnalysisChart;
"}

