{"path":"/home/rafid/devel/four_percentor/frontend/src/lib/calculation/index.ts","content":"// Frontend calculation utilities for retirement planning

export function calculateFutureValueWithContributions(
  currentSavings: number,
  monthlyContribution: number,
  annualReturnRate: number,
  years: number
): number {
  if (years <= 0) {
    return currentSavings;
  }

  const monthlyReturnRate = annualReturnRate / 12;
  const totalMonths = years * 12;

  // Future value of current savings (compound interest)
  const futureValueCurrent = currentSavings * Math.pow(1 + monthlyReturnRate, totalMonths);

  // Future value of monthly contributions (annuity formula)
  let futureValueContributions: number;
  if (monthlyReturnRate > 0) {
    futureValueContributions = monthlyContribution * 
      ((Math.pow(1 + monthlyReturnRate, totalMonths) - 1) / monthlyReturnRate);
  } else {
    futureValueContributions = monthlyContribution * totalMonths;
  }

  return futureValueCurrent + futureValueContributions;
}

export function estimateSocialSecurityBenefit(
  fullRetirementAgeBenefit: number,
  claimedAge: number,
  fullRetirementAge: number = 67
): number {
  if (claimedAge >= fullRetirementAge) {
    // Delaying beyond FRA increases benefit by ~8% per year
    const yearsDelayed = Math.max(0, claimedAge - fullRetirementAge);
    return fullRetirementAgeBenefit * (1 + 0.08 * yearsDelayed);
  } else {
    // Taking early reduces benefit by ~5% per month before FRA
    const monthsEarly = (fullRetirementAge - claimedAge) * 12;
    const reductionRate = 0.05 / 12;
    return fullRetirementAgeBenefit * Math.max(0.3, (1 - reductionRate * monthsEarly));
  }
}

export function calculateWithdrawalStrategy(
  totalSavings: number,
  yearsToLive: number,
  annualReturnRate: number
): { safeWithdrawal: number; balanceAtEnd: number } {
  const safeWithdrawal = totalSavings * 0.04;

  let balance = totalSavings;
  for (let year = 0; year < yearsToLive; year++) {
    balance = balance * (1 + annualReturnRate) - safeWithdrawal;
    if (balance <= 0) {
      balance = 0;
      break;
    }
  }

  return { safeWithdrawal, balanceAtEnd: Math.max(0, balance) };
}
"}

